#include<bits/stdc++.h>
using namespace  std;
long long a[505][505];
int b[10005];
int p,f,cc,ans=0;
int main(){
    cin>>p>>f>>cc;
    for(int i=1;i<=f;i++) {
        cin>>b[i];
    }
    int k=1;
    for(int i=1;i<=p;i++){
        for(int j=1;j<=p;j++){
            if(i==j) a[i][j]=0;
            else a[i][j]=INT_MAX;
        }
    }
    for(int i=1;i<=cc;i++){
        int x,y,z;
        cin>>x>>y>>z;
        a[x][y]=z;
        a[y][x]=z;
    }
    for(int k=1;k<=p;k++) for(int i=1;i<=p;i++) for(int j=1;j<=p;j++) a[i][j]=min(a[i][j],a[i][k]+a[k][j]);
    double ans=1e9;
    int bian=0;
    for(int i=1;i<=p;i++) {
        long long anns=0;
        for(int j=1;j<=f;j++){
            anns+=a[i][b[j]];
        }
        double da=anns/1.0/f;
        if(ans>da){
            ans=da;
            bian=i;
        }
    }
    cout<<bian;
}
